#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
using namespace std;
CI mx=41;
int f[mx][mx][mx][mx],nm[351],g[5],x;
int qp(int a,int b)
{
	int s=1;
	wh(b)
	{
		if(b&1)
		{
			s=s*a;
		}
		a=a*a;
		b>>=1;
	}
	return s;
}
signed main(void)
{
	IOS
	int n,m;
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>nm[i];
	}
	f[0][0][0][0]=nm[1];
	FOR(i,1,m)
	{
		cin>>x;
		g[x]++;
	}
	FOR(a,0,g[1])
	{
		FOR(b,0,g[2])
		{
			FOR(c,0,g[3])
			{
				FOR(d,0,g[4])
				{
					int r=1+a+b*2+c*3+d*4;
					if(a!=0)
					{
						f[a][b][c][d]=max(f[a][b][c][d],f[a-1][b][c][d]+nm[r]);
					}
					if(b!=0)
					{
						f[a][b][c][d]=max(f[a][b][c][d],f[a][b-1][c][d]+nm[r]);
					}
					if(c!=0)
					{
						f[a][b][c][d]=max(f[a][b][c][d],f[a][b][c-1][d]+nm[r]);
					}
					if(d!=0)
					{
						f[a][b][c][d]=max(f[a][b][c][d],f[a][b][c][d-1]+nm[r]);
					}
				}
			}
		}
	}
	cout<<f[g[1]][g[2]][g[3]][g[4]];
	return false;
}
